code = """import re, json, pandas as pd

recs = var_call_pJI2jSVkfozqo85UGeQHHcEw

def extract_state(desc):
    if not desc:
        return None
    m = re.search(r"\b([A-Z]{2})\b", desc.split(' in ')[-1])
    if m:
        return m.group(1)
    m = re.search(r",\s*([A-Z]{2})\b", desc)
    return m.group(1) if m else None

rows=[]
for r in recs:
    st = extract_state(r.get('description'))
    if st and st != 'AB':
        rows.append({'business_id': r['business_id'], 'state': st})

df = pd.DataFrame(rows)
state_counts = df.groupby('state').size().sort_values(ascending=False)
if state_counts.empty:
    out = {'state': None, 'wifi_business_count': 0, 'avg_rating': None}
    print('__RESULT__:')
    print(json.dumps(out))
    raise SystemExit

top_state = state_counts.index[0]
top_count = int(state_counts.iloc[0])
top_biz = df[df['state']==top_state]['business_id'].tolist()

# map businessid_X -> businessref_X
biz_refs = [b.replace('businessid_','businessref_') for b in top_biz]

# chunk to avoid huge IN clause
chunks = [biz_refs[i:i+5000] for i in range(0, len(biz_refs), 5000)]

print('__RESULT__:')
print(json.dumps({'top_state': top_state, 'wifi_business_count': top_count, 'business_refs_chunks': chunks}))"""

